public class Collatz {
    static int steps(int n) {
        int count = 0;
        while (n != 1) {
            n = (n % 2 == 0) ? n / 2 : 3 * n + 1;
            count++;
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(steps(1));
        System.out.println(steps(2));
        System.out.println(steps(6));
    }
}
